UPDATE voj_languages 
SET language_slug = #{languageSlug}, language_name = #{languageName}, language_compile_command = #{compileCommand}, language_run_command = #{runCommand}, language_enabled = #{enabled}, language_source_filename = #{sourceFilename}, language_time_multiplier = #{timeMultiplier}, language_memory_multiplier = #{memoryMultiplier}
WHERE language_id = #{languageId}
